153	            match PREVIEW.get().unwrap() {
154	                PreviewMode::Test(rwlock) => {
155	                    *rwlock.write().unwrap() = None;
156	                }
157	                PreviewMode::Normal(_) => {
158	                    unreachable!("FeaturesGuard should not exist when in Normal mode");
159	                }
160	            }
161	        }
