    pub no_emit_local: bool,

    /// Only include local path dependencies in the exported requirements.
    #[arg(
        long,
        alias = "only-install-local",
        conflicts_with = "no_emit_local",
        hide = true
    )]
    pub only_emit_local: bool,

    /// Do not emit the given package(s).
