    /// changes, but will not write the lockfile to disk.
    #[arg(long, conflicts_with = "frozen", conflicts_with = "locked")]
    pub dry_run: bool,

    #[command(flatten)]
    pub resolver: ResolverArgs,

    #[command(flatten)]
    pub build: BuildOptionsArgs,

