use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;
use uv_cache::{Cache, CacheBucket};
use uv_preview::{Preview, PreviewFeature};
use uv_warnings::warn_user;

/// Display a per-bucket breakdown of cache usage.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
    preview: Preview,
) -> Result<ExitStatus> {
    if !preview.is_enabled(PreviewFeature::CacheStats) {
        warn_user!(
            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
            PreviewFeature::CacheStats
        );
    }

    // Collect the size of each bucket.
    let buckets: Vec<(String, u64)> = CacheBucket::iter()
        .chain(std::iter::once(CacheBucket::Python))
        .map(|bucket| {
            let name = format!("{bucket}");
            let path = cache.bucket(bucket);
            let size = if path.exists() {
                DiskUsage::new(vec![path]).count_ignoring_errors()
            } else {
                0
            };
            (name, size)
        })
        .collect();

    let total_bytes: u64 = buckets.iter().map(|(_, size)| size).sum();

    // Determine the column width from the longest bucket name (or "total").
    let max_name_len = buckets
        .iter()
        .map(|(name, _)| name.len())
        .max()
        .unwrap_or(0)
        .max("total".len());

    // Print each bucket row.
    for (name, size) in &buckets {
        if human_readable {
            let (bytes, unit) = human_readable_bytes(*size);
            writeln!(
                printer.stdout_important(),
                "{name:<max_name_len$}  {bytes:.1}{unit}"
            )?;
        } else {
            writeln!(
                printer.stdout_important(),
                "{name:<max_name_len$}  {size}"
            )?;
        }
    }

    // Separator line.
    writeln!(printer.stdout_important(), "{:-<max_name_len$}  ---", "")?;

    // Total row.
    if human_readable {
        let (bytes, unit) = human_readable_bytes(total_bytes);
        writeln!(
            printer.stdout_important(),
            "{:<max_name_len$}  {bytes:.1}{unit}",
            "total"
        )?;
    } else {
        writeln!(
            printer.stdout_important(),
            "{:<max_name_len$}  {total_bytes}",
            "total"
        )?;
    }

    Ok(ExitStatus::Success)
}

